## Optional Chaining & Nullish Coalescing

```js
// ❌ Verbose guard chains
const city = user && user.address && user.address.city;
const count = data.count !== null && data.count !== undefined ? data.count : 0;

// ✅ Optional chaining + nullish coalescing
const city = user?.address?.city;
const count = data.count ?? 0;        // ?? only triggers on null/undefined, not 0 or ''
const label = config.label ?? 'Default';

// ✅ Method calls and dynamic access
const len = arr?.length;
const val = obj?.[key];
const result = api?.fetch?.();

// ✅ Nullish assignment — set only if currently null/undefined
config.timeout ??= 5000;
```

**Key difference: ?? vs ||**
```js
0 ?? 'default'   // → 0    (0 is not null/undefined)
0 || 'default'   // → 'default' (0 is falsy)
'' ?? 'default'  // → ''   (empty string is valid)
'' || 'default'  // → 'default' (empty string is falsy)
```

## Destructuring Patterns

```js
// Object destructuring with rename + default
const { name: userName = 'Anonymous', role = 'user', ...rest } = user;

// Function parameter destructuring
function createUser({ name, email, role = 'member', notify = true } = {}) {
  // ...
}

// Array destructuring with skip
const [first, , third] = items;
const [head, ...tail] = list;

// Nested destructuring
const { address: { city, zip = '00000' } } = user;

// Swap without temp variable
[a, b] = [b, a];

// Destructure in loops
for (const [key, value] of Object.entries(obj)) { /* ... */ }
for (const { id, name } of users) { /* ... */ }
```

**Rules:**
- Always provide a default `= {}` for destructured parameters so the function is callable with no args
- Limit destructuring depth to 2 levels — deeper nesting hurts readability

## Async/Await & Promise Patterns

### Basic async/await
```js
async function fetchUser(id) {
  try {
    const response = await fetch(`/api/users/${id}`);
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    return await response.json();
  } catch (err) {
    console.error('fetchUser failed:', err);
    throw err; // re-throw — don't swallow
  }
}
```

### Parallel fetches
```js
// ✅ Run in parallel, fail if any fails
const [user, posts] = await Promise.all([fetchUser(id), fetchPosts(id)]);

// ✅ Run in parallel, get all results regardless of failure
const results = await Promise.allSettled([fetchA(), fetchB(), fetchC()]);
const succeeded = results.filter(r => r.status === 'fulfilled').map(r => r.value);

// ✅ First success wins
const data = await Promise.any([mirror1(), mirror2(), mirror3()]);
```

### AbortController for cancellable fetch
```js
function fetchWithCancel(url) {
  const controller = new AbortController();
  const promise = fetch(url, { signal: controller.signal }).then(r => r.json());
  return { promise, cancel: () => controller.abort() };
}

// In React
useEffect(() => {
  const { promise, cancel } = fetchWithCancel('/api/data');
  promise.then(setData).catch(err => { if (err.name !== 'AbortError') setError(err); });
  return cancel; // cleanup on unmount / dep change
}, []);
```

**Rules:**
- Never `await` inside a loop when items are independent — collect promises and `await Promise.all()`
- Always handle rejections — unhandled promise rejections crash Node 15+

## ES Modules Best Practices

### Prefer named exports
```js
// ✅ Named exports — refactor-safe, tree-shakeable
export function formatDate(date) { /* ... */ }
export function parseDate(str)   { /* ... */ }
export const DATE_FORMAT = 'YYYY-MM-DD';

// ❌ Single default of an object — breaks tree-shaking
export default { formatDate, parseDate, DATE_FORMAT };
```

### Re-exporting from barrel files (use sparingly)
```js
// src/utils/index.js
export { formatDate, parseDate } from './date';
export { slugify, truncate }   from './string';
// ⚠️ Barrel files hurt bundler tree-shaking — prefer direct imports in perf-critical code
```

### Dynamic import for code splitting
```js
// Load heavy module only when needed
const { Chart } = await import('./chart');

// React lazy
const HeavyPage = lazy(() => import('./pages/HeavyPage'));
```

### Import assertions (JSON)
```js
import data from './config.json' with { type: 'json' };
```

**Rules:**
- One module = one responsibility
- No circular imports — if A imports B and B imports A, extract shared logic to C
- Keep barrel `index.js` files optional — direct imports are always acceptable

## Structured Error Handling

### Custom error classes
```js
class AppError extends Error {
  constructor(message, { code, status = 500, cause } = {}) {
    super(message, { cause }); // native cause chaining (ES2022)
    this.name = 'AppError';
    this.code = code;
    this.status = status;
  }
}

class ValidationError extends AppError {
  constructor(message, fields) {
    super(message, { code: 'VALIDATION_FAILED', status: 400 });
    this.name = 'ValidationError';
    this.fields = fields;
  }
}

class NotFoundError extends AppError {
  constructor(resource) {
    super(`${resource} not found`, { code: 'NOT_FOUND', status: 404 });
    this.name = 'NotFoundError';
  }
}
```

### Usage
```js
async function getUser(id) {
  const user = await db.users.findById(id);
  if (!user) throw new NotFoundError('User');
  return user;
}

try {
  const user = await getUser(req.params.id);
  res.json(user);
} catch (err) {
  if (err instanceof AppError) {
    res.status(err.status).json({ error: err.message, code: err.code });
  } else {
    logger.error(err); // unexpected — log full stack
    res.status(500).json({ error: 'Internal server error' });
  }
}
```

**Rules:**
- Never: `catch (e) {}` — always handle or rethrow
- Never: `catch (e) { console.log(e) }` without rethrowing — silent failures
- Always chain `cause` when wrapping: `throw new AppError('msg', { cause: originalErr })`
- In async functions: if you don't know what to do with an error, rethrow it

## Immutable Data Patterns

### Arrays — always return new
```js
// ❌ Mutation
array.push(item);
array.splice(idx, 1);
array.sort();

// ✅ Immutable equivalents
const withItem   = [...array, item];
const withoutIdx = array.filter((_, i) => i !== idx);
const sorted     = [...array].sort();

// New ES2023 methods (return new array)
const updated = array.with(idx, newValue);
const reversed = array.toReversed();
const sorted2  = array.toSorted();
const spliced  = array.toSpliced(idx, 1, newItem);
```

### Objects — spread for shallow, structuredClone for deep
```js
// Shallow update
const updated = { ...user, email: 'new@example.com' };

// Nested update
const updated = {
  ...user,
  address: { ...user.address, city: 'London' },
};

// Deep clone (replaces JSON parse/stringify — handles Dates, Sets, Maps, undefined)
const clone = structuredClone(original);
```

### Frozen constants
```js
const STATUS = Object.freeze({ PENDING: 'pending', DONE: 'done', FAILED: 'failed' });
const CONFIG = Object.freeze({ MAX_RETRIES: 3, TIMEOUT: 5000 });
```

**Rule:** If you catch yourself doing `arr.push()` or `obj.key = val` in shared state — stop. Return a new value.

## Object.groupBy / Map.groupBy (ES2024)

```js
const users = [
  { name: 'Alice', role: 'admin' },
  { name: 'Bob',   role: 'user' },
  { name: 'Carol', role: 'admin' },
];

// Object.groupBy → plain object with string keys
const byRole = Object.groupBy(users, u => u.role);
// { admin: [Alice, Carol], user: [Bob] }

// Map.groupBy → Map (allows object keys)
const byLength = Map.groupBy(users, u => u.name.length);

// Replaces the common reduce pattern:
// const byRole = users.reduce((acc, u) => { (acc[u.role] ??= []).push(u); return acc; }, {});
```

**Polyfill for older environments:**
```js
if (!Object.groupBy) {
  Object.groupBy = (arr, fn) =>
    arr.reduce((acc, item) => { (acc[fn(item)] ??= []).push(item); return acc; }, {});
}
```

**Support:** Chrome 117+, Firefox 119+, Safari 17.4+. Node 21+.

## Closures and Module Pattern

### Counter with private state
```js
function createCounter(initial = 0) {
  let count = initial; // private — not accessible outside

  return {
    increment: () => ++count,
    decrement: () => --count,
    reset:     () => { count = initial; },
    value:     () => count,
  };
}

const counter = createCounter(10);
counter.increment(); // 11
counter.value();     // 11
counter.count;       // undefined — truly private
```

### Memoization via closure
```js
function memoize(fn) {
  const cache = new Map();
  return function (...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key);
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

const expensiveCalc = memoize((n) => { /* heavy work */ return n * n; });
```

### IIFE for one-off isolation
```js
const result = (() => {
  const temp = heavyComputation();
  return transform(temp);
})();
// temp is never in outer scope
```

## Modern Array Methods

```js
// at() — negative index access
const last = arr.at(-1);
const secondLast = arr.at(-2);

// flat / flatMap
const nested = [[1, 2], [3, [4, 5]]];
nested.flat();    // [1, 2, 3, [4, 5]]  (depth 1)
nested.flat(2);   // [1, 2, 3, 4, 5]

const sentences = ['Hello world', 'Foo bar'];
sentences.flatMap(s => s.split(' ')); // ['Hello', 'world', 'Foo', 'bar']

// findLast / findLastIndex (ES2023)
const lastEven = arr.findLast(x => x % 2 === 0);
const lastEvenIdx = arr.findLastIndex(x => x % 2 === 0);

// Immutable mutators (ES2023)
const arr = [3, 1, 4, 1, 5];
arr.toSorted()         // new sorted array, arr unchanged
arr.toReversed()       // new reversed array
arr.with(2, 99)        // [3, 1, 99, 1, 5] — new array with index 2 = 99
arr.toSpliced(1, 2)    // [3, 1, 5] — remove 2 at index 1

// Array.from with mapping
const squares = Array.from({ length: 5 }, (_, i) => i * i); // [0, 1, 4, 9, 16]
const chars   = Array.from('hello'); // ['h', 'e', 'l', 'l', 'o']
```

## structuredClone — Native Deep Copy

```js
// ❌ Old approach — drops undefined, Dates become strings, fails on circular
const clone = JSON.parse(JSON.stringify(original));

// ✅ Native — handles more types correctly
const clone = structuredClone(original);

// Works with:
const obj = {
  date: new Date(),
  set: new Set([1, 2, 3]),
  map: new Map([['a', 1]]),
  nested: { arr: [1, 2, 3] },
  undef: undefined,
};
const deep = structuredClone(obj);
deep.date instanceof Date // true
deep.set instanceof Set   // true

// Transferable objects (moves ownership — zero-copy for ArrayBuffer)
const buffer = new ArrayBuffer(1024);
const transferred = structuredClone(buffer, { transfer: [buffer] });
// buffer is now detached (empty) — transferred has the data
```

**Limitations:** Cannot clone functions, DOM nodes, class instances with prototype methods.

**Support:** All modern browsers + Node 17+.
